import json
with open('/root/books/webapp/books.json') as f:
    data = json.load(f)

new_desc = {
    376: 'Начинали с авиадвигателей — перешли к мотоциклам и автомобилям. История бренда который поставил удовольствие от вождения в центр всего.',
    377: 'Фердинанд создал Volkswagen для Гитлера. Его сын создал спортивный автомобиль мечты. История о семье, гонках и самом прибыльном автопроизводителе мира.',
    378: 'Молодой иммигрант без денег придумал непотопляемые часы — и сделал их символом абсолютного успеха. История о дефиците, горах и дне океана.',
    379: 'Два инженера в разрушенном Токио, $500 капитала и мечта. Walkman, PlayStation, кинокамеры — как Япония стала технологической сверхдержавой.',
    383: 'Коко Шанель освободила женщин от корсетов и создала маленькое чёрное платье. История из приюта до главного имени в мировой моде.',
    384: 'Pepsi дважды банкротился и всю жизнь догонял Coca-Cola. История о том как вечный второй построил глобальную империю напитков и снеков.',
}

for book in data:
    if book['id'] in new_desc:
        book['description'] = new_desc[book['id']]

additions = {
    # 376 BMW
    (376,0): ' Логотип — стилизованный пропеллер в баварских цветах (синий и белый). BMW делал двигатели для самолётов Первой мировой — после поражения Германии запрет на авиапроизводство толкнул к мотоциклам.',
    (376,1): ' Isetta — «яйцо на колёсах» с дверью спереди — спасла BMW от поглощения Mercedes. 136 000 штук продано в 1955-1962. Маленькая машина для бедных спасла компанию делающую машины для богатых.',
    (376,2): ' New Class 1500 вернул BMW к спортивным корням. Именно тогда родилось ДНК: управляемость важнее комфорта. Принцип «Ultimate Driving Machine» заложен в этой модели 1961 года.',
    (376,3): ' M означает Motorsport. BMW M3 — один из самых продаваемых спортивных седанов в истории. M-версии дороже базы на 30-50% — и всегда в листе ожидания. Гоночное подразделение монетизировалось лучше чем сами гонки.',
    (376,4): ' «Крис Бэнгл уничтожил BMW» — писали критики в 2001 году. «Бэнгл сохранил BMW» — написали в 2010. Дизайн который ненавидели — оказался самым скопированным в индустрии. Авангард всегда отвергается сначала.',
    (376,5): ' Rover продан в 2000 году за £10. Не за $10 миллионов — за £10. Потеря £3 миллиарда за 6 лет. MINI и Land Rover (Rolls-Royce отдельно) сохранены. BMW научился у провала как строить портфель брендов.',
    (376,6): ' i3 использует карбон (CFRP) в кузове — впервые в массовом производстве. Технология слишком дорогая для объёмов. i3 — лаборатория которую BMW окупил через знания, не через продажи.',
    (376,7): ' В Лейпциге работают роботы BMW и люди с инвалидностью бок о бок — эргономика адаптирована для обоих. 25% сотрудников старше 50 лет. Это не благотворительность — это исследование продуктивности.',
    (376,8): ' BMW, Mercedes, Audi — «премиальная тройка» которая делает 80% люксовых продаж. Но Китай меняет картину: Li Auto, NIO, BYD берут долю у всех трёх. Немецкая тройка под давлением впервые за 50 лет.',
    (376,9): ' BMW Group включает MINI и Rolls-Royce. Самая высокая маржинальность в классе — 11,5% на автомобиль. «Радость от вождения» из слогана превратилась в финансовую стратегию.',

    # 377 Porsche
    (377,0): ' Порше создал Beetle по заказу Гитлера — «народный автомобиль» за 990 рейхсмарок. После войны провёл 20 месяцев во французской тюрьме. Вышел — и продолжил проектировать. Единственное что умел.',
    (377,1): ' Первый 356 собран из запчастей Volkswagen Beetle — буквально. Двигатель VW, подвеска VW, коробка VW. Ферри переставил мотор спереди назад и получил спортивный автомобиль.',
    (377,2): ' 911 — единственный автомобиль с задним мотором в серийном производстве. Все говорили что это опасно — покупатели говорили что это прекрасно. 60 лет споров о том умрёт ли 911. Не умер.',
    (377,3): ' Фердинанд Пих (внук Фердинанда Порше) поглотил Volkswagen через финансовые манипуляции. Потом Volkswagen поглотил Porsche. Семейная война длилась 40 лет. В конце — все в одной корпорации.',
    (377,4): ' Cayenne — предательство для пуристов. Спасение для компании. Продажи выросли втрое. Сегодня Cayenne и Macan дают 60% выручки Porsche. Без SUV не было бы 911. Это неудобная правда бренда.',
    (377,5): ' 19 побед в Ле-Мане. Ближайший конкурент — Audi с 13. Porsche выиграл больше всех. Гоночная репутация обеспечивает 20% премии к цене серийных автомобилей. Гонки — лучший маркетинг.',
    (377,6): ' Taycan — быстрее 911 в разгоне. Электромотор даёт крутящий момент мгновенно. Porsche решил проблему которой боялись все: как сделать электромобиль эмоциональным. Через звук, педаль и разгон 2,8 секунды.',
    (377,7): ' IPO Porsche в 2022 году — €72 за акцию, капитализация €75 миллиардов. Это больше чем Ford и GM вместе. 320 000 автомобилей в год стоят больше чем 6 миллионов. Маржинальность на уровне LVMH.',
    (377,8): ' «Porsche нет дороже твоей» — русская поговорка из 1990-х. В поп-культуре от Канье до Джея-Зи. Porsche — автомобиль успеха в глобальном культурном коде даже там где его никто не видел.',
    (377,9): ' Чистая маржа Porsche AG — около 18%. Для сравнения: Apple 25%, Toyota 8%, Volkswagen 6%. Porsche зарабатывает больше чем любой автопроизводитель в мире относительно выручки.',

    # 378 Rolex
    (378,0): ' Вилсдорф перенёс компанию из Лондона в Женеву в 1919 году чтобы избежать британских налогов. Швейцарская ассоциация стала частью идентичности бренда — хотя основатель был немцем.',
    (378,1): ' Первое испытание: пловчиха Мерседес Глейтце переплыла Ла-Манш в 1927 году с Oyster на запястье. Часы показывали точное время. Реклама в Times на следующий день создала бренд «прочности».',
    (378,2): ' До 1931 года часы нужно было ежедневно заводить вручную. Perpetual автоматически заряжается от движения запястья. Rolex сделал часы «живыми» — они работают пока их носишь.',
    (378,3): ' Oyster Perpetual покорил Эверест (1953, Хиллари) и Марианскую впадину (1960, Пикар). Два самых крайних места на Земле — один бренд. Это не случайность. Это 20-летняя стратегия доказательства.',
    (378,4): ' Submariner водонепроницаем до 300 метров — больше чем любой дайвер нырнёт. Практическая избыточность стала символом: «если для этого — то для чего угодно». James Bond носил Submariner с 1962 года.',
    (378,5): ' Rolex не продаёт в своих бутиках — продаёт через авторизованных дилеров. Лист ожидания на популярные модели — 2-5 лет. Дефицит создаётся намеренно: производство можно увеличить, но не стоит.',
    (378,6): ' Уимблдон, Формула-1, гольф — Rolex хронометрирует события где время буквально решает исход. Это не просто спонсорство. Это контекст: «точность, когда ставки максимальны».',
    (378,7): ' В Зимбабве в 2000-х гиперинфляция: люди хранили сбережения в Rolex. В России в 1990-х — аналогично. Часы как портативное хранилище ценности — эффект который Rolex не планировал, но принял.',
    (378,8): ' Hans Wilsdorf Foundation не платит налогов как благотворительный фонд. Публичной отчётности нет. Никто точно не знает сколько стоит Rolex. Тайна владения — часть бренда тайны формулы.',
    (378,9): ' Submariner на вторичном рынке продаётся за 150-200% от розницы. Daytona — за 300%. Rolex — единственный «товар» который дорожает сразу после покупки. Это превратило часы в финансовый инструмент.',

    # 379 Sony
    (379,0): ' Tokyo Tsushin Kogyo (Токийская телекоммуникационная инженерная корпорация) — так называлась компания до 1958 года. Морита переименовал в Sony: sonus (лат. «звук») + sunny (англ. «солнечный»). Имя для американского рынка.',
    (379,1): ' Sony нарушил патент американской AT&T на транзистор — купил лицензию за $25 000 и создал первый карманный радиоприёмник. Американцы хотели использовать транзисторы в военных целях. Sony — в музыкальных.',
    (379,2): ' Председатель Sony Масару Ибука хотел слушать оперу в самолётах. Walkman создан для одного человека. За 30 лет продано 400 миллионов штук. Лучшие продукты созданы для конкретного желания а не для рынка.',
    (379,3): ' VHS от JVC выиграл не потому что лучше — потому что дольше пишет (4 часа против 1 у Betamax). Sony отказался лицензировать Betamax другим производителям. JVC лицензировал всем. Открытость победила качество.',
    (379,4): ' Nintendo отказала Sony — и создала конкурента. PlayStation вышел в 1994 году и продался в 102 миллиона штук. Nintendo дала Sony бизнес стоимостью триллион долларов через отказ от сотрудничества.',
    (379,5): ' AIBO стоил $2500 в 1999 году. Раскупили за несколько минут. Sony создал концепцию «эмоциональной технологии» за 20 лет до того как это стало трендом. Проект закрыт в 2006 и возрождён в 2018.',
    (379,6): ' Sony пропустил iPod, плоские экраны (Panasonic выиграл), смартфоны (Samsung выиграл). Причина: вертикальная интеграция — Sony боялся конкурировать с собственным музыкальным лейблом.',
    (379,7): ' Каждый второй смартфон в мире имеет сенсор Sony. iPhone использует сенсоры Sony. Sony — невидимая инфраструктура визуального мира. Самый важный компонент которого никто не видит.',
    (379,8): ' Sony купила Columbia Pictures в 1989 году за $3,4 миллиарда. Spider-Man принёс $10+ миллиардов в кино. Японская электронная компания случайно стала голливудской студией — и не пожалела.',
    (379,9): ' Sony Group: электроника, музыка, кино, игры, финансы. Каждый сегмент независим. PlayStation — самый прибыльный. Сенсоры — стратегически важнейший. Sony перестала быть «TV-компанией» и стала конгломератом.',

    # 380 Audi
    (380,0): ' Horch, Audi, DKW, Wanderer. Horch по-немецки «слушай»; Audi — тот же смысл по-латыни. Четыре кольца = четыре объединившиеся компании. Слияние выживших в Великую депрессию.',
    (380,1): ' Quattro дебютировал на ралли: 1980-1982 Audi Quattro выиграл чемпионат мира по ралли. Постоянный полный привод — radical в эпоху заднеприводных машин. Технология для гонок стала серийной за 3 года.',
    (380,2): ' Vorsprung durch Technik с 1971 года. Англичане не переводили — оставили по-немецки. Иностранный слоган создал образ немецкой инженерной серьёзности лучше чем любой перевод.',
    (380,3): ' Победа в Ле-Мане 2000 года с дизелем опровергла стереотип «дизель = грузовик». Audi выиграл Ле-Ман 13 раз. Дизельные технологии из Ле-Мана пошли в серийные автомобили. Гонки — НИОКР Audi.',
    (380,4): ' Volkswagen закрыл информацию от регуляторов 7 лет. Штраф $33 миллиарда. Репутация утрачена. Дизельгейт убил дизель в Европе — регуляторы ужесточили нормы. Audi сам уничтожил свой главный продукт.',
    (380,5): ' Виртуальная приборная панель Audi (Virtual Cockpit) — первая полностью цифровая в серийном автомобиле (2014). Сегодня стандарт отрасли. Audi создал новый стандарт интерьера — конкуренты скопировали.',
    (380,6): ' e-tron продаётся хуже ожиданий: слабее на заряде, тяжелее, медленнее Tesla. Audi признал отставание. Проблема: «Vorsprung durch Technik» обязывает лидировать — а в электро Audi не лидер.',
    (380,7): ' Audi в Китае с 1988 года — партнёрство с FAW. Audi 100 стал официальным автомобилем китайских чиновников в 1990-х. «Чиновничий Audi» — культурный феномен создавший бренд в Китае до любого маркетинга.',
    (380,8): ' Audi Sport выиграл Ле-Ман 13 раз, DTM 7 раз. Lamborghini (принадлежит Audi) выиграл Хуракан GT3 многократно. Audi — тихий чемпион моторспорта с богатейшей гоночной историей.',
    (380,9): ' Audi AG управляет Lamborghini, Ducati и частью Bentley. Выручка €69 млрд. Volkswagen Group — крупнейший автопроизводитель мира использует Audi как технологический локомотив группы.',

    # 381 Ford
    (381,0): ' Форд не первый кто использовал конвейер — Ransom Olds сделал это в 1901 году. Форд первый кто применил ДВИЖУЩИЙСЯ конвейер. Разница: скорость сборки с 12,5 часа до 93 минут. Это и есть революция.',
    (381,1): ' Model T выпускалась 19 лет — дольше любого автомобиля в истории США. За 15 миллионов штук цена упала с $850 до $280. Массовое производство само создало рынок через снижение цены.',
    (381,2): ' $5 в день — Форд платил вдвое больше рынка. Цель: снизить текучесть кадров с 370% в год до разумной. Побочный эффект: рабочие Ford могли купить Ford. Рабочий как потребитель — новая экономика.',
    (381,3): ' 400 000 заказов в первые два дня. Mustang создал категорию «пони-кар»: доступный спортивный автомобиль. Chevrolet Camaro — прямой ответ. Культурные войны 1960-х разыгрывались через автомобили.',
    (381,4): ' Ford потратил $9,5 миллиарда на GT40 программу. Победил в Ле-Мане 4 раза подряд 1966-1969. Ярость Форда от отказа Энцо стоила сотни миллионов — и дала компании гоночную легенду на 50 лет.',
    (381,5): ' Edsel — имя сына Генри Форда. Вертикальный хром «туалетного сиденья» и странная маркетинговая кампания. Потеря $350 миллионов. Edsel стал синонимом провала — учебный пример MBA до сегодня.',
    (381,6): ' F-150 — самое продаваемое транспортное средство в США 47 лет подряд. Маржа на один F-150 больше чем на три Fusion. Ford намеренно сворачивает седаны — деньги в грузовиках и кроссоверах.',
    (381,7): ' Mustang Mach-E вызвал ярость у пуристов: «Mustang должен быть с V8». Ford ответил: Mach-E продаётся лучше любого Mustang за последние 20 лет. Имя продало электромобиль без традиционной рекламы.',
    (381,8): ' Семья Форд контролирует 40% голосующих акций через акции класса B. Уильям Клэй Форд-младший — исполнительный председатель. Компания публичная но управляется как семейная. Редкость для такого масштаба.',
    (381,9): ' Ford выходит из Европы (продал Ranger и Transit в коммерческих целях), фокусируется на США. Инвестиции $50 млрд в электрификацию к 2026 году. Ford меняется медленно — как и всегда. Выживает — как всегда.',

    # 382 Louis Vuitton
    (382,0): ' Луи прошёл 400 км пешком за 2 года — работал слугой по дороге. В Париже стал упаковщиком вещей для аристократии. Его умение раскладывать без складок ценилось как искусство. Из упаковщика — в основатели.',
    (382,1): ' До LV чемоданы были с выпуклым верхом — нельзя складывать. Плоский сундук Витона позволил штабелировать багаж. Революция в логистике путешествий XIX века. Железные дороги создали рынок — LV его взял.',
    (382,2): ' Монограмма LV создана для борьбы с копиями — но копируется больше всего в мире. Это парадокс люкса: чем узнаваемее защита от подделок — тем выгоднее делать подделки.',
    (382,3): ' LVMH = Louis Vuitton Moёt Hennessy. Бернар Арно купил контроль в 1990 году. Сегодня LVMH владеет 75 брендами: Dior, Givenchy, Bulgari, Tiffany. LV — флагман империи стоимостью $500 миллиардов.',
    (382,4): ' Neverfull, Speedy, Alma — LV сумки дорожают на 8-10% в год стабильно. Speedy 30 из 1950-х стоила $35. Сегодня — $1500. Перепродажная стоимость превышает розничную у редких моделей.',
    (382,5): ' Аблох умер в 2021 году. При нём продажи выросли на 25%. Streetwear встретился с люксом — и выиграл оба рынка. LV доказал: если менять осторожно — теряешь молодых. Если смело — выигрываешь всех.',
    (382,6): ' Монограмма на трусах Lil Wayne, бейсболках рэперов, пляжных полотенцах — в 1990-х LV боролась с этим. После Вирджила — приняла. Уличная культура теперь часть нарратива бренда, а не угроза ему.',
    (382,7): ' Мастер-ателье в Аньере под Парижем — там хранятся сундуки для частных клиентов. LV сделал 6000-долларовую сумку для Барака Обамы. Кастомизация как услуга для тех кто выше «просто LV».',
    (382,8): ' LV Parfums запустил Les Parfums Louis Vuitton в 2016 году — 7 ароматов по €200+. Первый парфюмер с 1987 года (Бернар Арно запретил раньше). 8 лет решение о парфюмерии — осторожность окупилась.',
    (382,9): ' Louis Vuitton — бренд №1 по стоимости в моде: $47 миллиардов по Interbrand. Обеспечивает 30-35% выручки всего LVMH. Один бренд кормит крупнейшую империю роскоши в мире.',

    # 383 Chanel
    (383,0): ' Имя «Коко» — прозвище из кабаре: пела песни о девушке и коте. «Qui qu\'a vu Coco» — «Кто видел Коко». Официально имя не раскрывалось — тайна усиливала образ. Легенда начиналась с имени.',
    (383,1): ' Vogue назвала маленькое чёрное платье «фордовским» — как Model T: практичным и доступным для всех. Шанель создала демократию в люксе за 30 лет до того как это стало концепцией.',
    (383,2): ' Шанель выбрала № 5 из 10 образцов Бо — по суеверию. Первый аромат содержавший альдегиды — синтетические молекулы. Революция: не цветочный букет а «запах женщины». Мэрилин Монро сказала что носит только его.',
    (383,3): ' Шанель ввела брюки для женщин в 1910-х — скандал. Вязаные jersey-ткани из мужских материалов. Маленькая шляпка вместо огромной. Каждое нововведение было политическим актом свободы.',
    (383,4): ' Шанель жила с немецким офицером в оккупированном Париже — коллаборационизм. Арестована после освобождения, выпущена через несколько часов (по слухам — вмешался Черчилль). Вернулась в моду в 1954 в 71 год.',
    (383,5): ' Лагерфельд не изменил ДНК Chanel — он его усилил. Тысячи вариаций твидового костюма. Чёрно-белая палитра. «Coco» духи. Каждый сезон — манифест верности архиву плюс один современный жест.',
    (383,6): ' Сумка 2.55 стоит €9000 сегодня. В 1955 году — $220. Перепродаётся за €14 000-20 000. Chanel поднимает цены на 30-40% в год последние 5 лет — и продажи не падают. Спрос превышает предложение.',
    (383,7): ' Chanel принадлежит братьям Вертхаймер — потомкам партнёра Шанель ещё с 1920-х. Оценка бренда — $13-15 миллиардов. Частная компания без давления квартальных отчётов — редкость в люксе.',
    (383,8): ' Fashion, Fragrance, Beauty — три равно сильных столба. J12 часы в 2000 году — четвёртый. Chanel единственный дом мод где парфюмерия (No.5) важнее одежды. 70% выручки — не подиум.',
    (383,9): ' Virginie Viard — преемница Лагерфельда с 2019 года. Тихая, преданная архиву. Продажи рекордные. Chanel после Карла доказал: бренд с 110-летней историей не зависит от одного творца.',

    # 384 Pepsi
    (384,0): ' Напиток назван из-за пепсина и орехов кола. Первое банкротство 1923, второе 1931. После второго — продан за $35 000. Покупатель перепродал в 1933 году. История Pepsi — история выживания вопреки.',
    (384,1): ' В 1934 году Pepsi начал продавать 12 унций за 5 центов — как 6 унций Coca-Cola. Слоган «Twice as much for a nickel» стал гимном в эпоху Депрессии. Ценность а не вкус стала стратегией.',
    (384,2): ' «Выбор нового поколения» — Pepsi впервые напрямую атаковал не продукт Coca-Cola а её аудиторию. Старое против молодого. Это переопределило правила войны брендов: нападай на демографию конкурента.',
    (384,3): ' Слепые тесты Pepsi выигрывал 57:43. Проблема: в магазине человек берёт Coca-Cola. Парадокс Pepsi — победа в лаборатории и поражение в жизни. Маркетологи назвали это «Pepsi Paradox».',
    (384,4): ' Frito-Lay: Doritos, Lay\'s, Cheetos, Ruffles. PepsiCo зарабатывает больше на снеках чем на напитках. Pepsi Cola — 25% выручки. Frito-Lay — 30%. Pepsi перестала быть «просто газировкой» в 1990-х.',
    (384,5): ' Michael Jackson сжёг волосы во время съёмок Pepsi-рекламы в 1984 году. Pepsi заплатил $1,5 миллиона и продолжил партнёрство. Потом Бритни — $50 миллионов за 10 лет. Pop-music и Pepsi неразделимы.',
    (384,6): ' Pepsi единственная компания выигравшая от провала конкурента. New Coke 1985 года: Pepsi объявил «победу в Cola Wars» прежде чем Coca-Cola вернул Classic. Маркетинговая случайность стала легендой.',
    (384,7): ' Gatorade: 85% рынка спортивных напитков США. Aquafina: топ-3 воды. Tropicana: №1 апельсиновый сок. Lipton (совместно с Unilever): №1 чайные напитки. PepsiCo — незаметная монополия в каждом холодильнике.',
    (384,8): ' Pepsi-Cola появилась в СССР в 1972 году — первый западный продукт в стране. Оплата бартером: советское правительство платило водкой «Столичная» и кораблями. Pepsi торговала кораблями на металлолом.',
    (384,9): ' PepsiCo работает в 200 странах. Но Coca-Cola по-прежнему лидирует в газировке. Pepsi выиграл диверсификацией: PepsiCo крупнее Coca-Cola Company по выручке ($91 vs $46 млрд). Другая игра — другой счёт.',

    # 385 Ferrero
    (385,0): ' Пьетро Ферреро создал Pasta Gianduja — предшественник Nutella — как доступную альтернативу шоколаду в дефиците Второй мировой. Лесные орехи Пьемонта стали основой шоколадной империи.',
    (385,1): ' Nutella продаётся 365 000 тонн в год. Франция потребляет 26% мирового объёма. Каждые 2,5 секунды продаётся банка. День Nutella — 5 февраля — отмечают в 75 странах.',
    (385,2): ' Kinder Surprise запрещён в США — «несъедобный объект внутри еды». Ferrero судился с FDA 40 лет и не выиграл. Но Kinder Joy (без игрушки внутри) продаётся. Бюрократия не победила — компромисс нашёлся.',
    (385,3): ' Raffaello назван в честь художника Рафаэля — белый, изысканный, итальянский. Mon Cheri с вишней в ликёре — символ романтики с 1956 года. Ferrero создаёт не продукты — отдельные эмоциональные вселенные.',
    (385,4): ' Золотая фольга Ferrero Rocher — дипломатический символ с 1982 года. Реклама с послом («Посол принимает») сделала продукт атрибутом официальных приёмов. Шоколад как статус — не вкус.',
    (385,5): ' Ferrero принадлежит семье Ферреро: Микеле умер в 2015 году, наследники продолжают. Без публичной отчётности компания инвестирует в качество не в квартальную прибыль. Частная форма позволяет это.',
    (385,6): ' Butterfinger, Baby Ruth, Nerds (от Nestle) — Ferrero купил американский сегмент сладостей за $2,8 млрд. Nutella-компания теперь продаёт конфеты детства в США. Тихая глобализация без фанфар.',
    (385,7): ' Турция производит 70% мирового фундука. Ferrero — крупнейший покупатель. Контракты с фермерами на 10 лет вперёд, инвестиции в агрономию. Ferrero управляет своим сырьём как стратегическим активом.',
    (385,8): ' Вкус Nutella стандартизирован: ±2% по сладости и ±1% по ореховости. Каждая банка в любой стране идентична. Производственные стандарты строже фармацевтических. Тайна рецептуры — дополнительная защита.',
    (385,9): ' Ferrero входит в топ-3 кондитерских компаний мира (Mars, Mondelez, Ferrero). Nutella на завтраке в 100 странах. Пьетро Ферреро открыл кондитерскую в 1942 году — внуки управляют империей.',
}

for book in data:
    if book['id'] in new_desc:
        book['description'] = new_desc[book['id']]

for book in data:
    bid = book['id']
    for i, t in enumerate(book['thoughts']):
        if (bid, i) in additions:
            t['example'] = t['example'] + additions[(bid, i)]

with open('/root/books/webapp/books.json', 'w') as f:
    json.dump(data, f, ensure_ascii=False)

# Trim > 820
ids = list(range(376, 386))
changed = False
for book in data:
    if book['id'] not in ids:
        continue
    for t in book['thoughts']:
        ex = t['example']
        if len(ex) > 820:
            pos = ex[:815].rfind('.')
            if pos > 700:
                t['example'] = ex[:pos+1]
                changed = True

if changed:
    with open('/root/books/webapp/books.json', 'w') as f:
        json.dump(data, f, ensure_ascii=False)

for book in data:
    if book['id'] in ids:
        dlens = len(book['description'])
        tlens = [len(t['example']) for t in book['thoughts']]
        t_bad = [(i,l) for i,l in enumerate(tlens) if l < 700 or l > 820]
        d_ok = 125 <= dlens <= 150
        status = 'OK' if d_ok and not t_bad else f'BAD desc={dlens} t={t_bad}'
        print(f'ID={book["id"]:3d} {book["title"][:18]:18s}: {status}')
